import{_ as r,C as i,o as e,c as h,a2 as a,b as s,w as o,a as u,E as q,a3 as n}from"./chunks/framework.Crpw6aS5.js";const E=JSON.parse('{"title":"多元化与集中投资","description":"分散风险还是集中持股？巴菲特的策略演变","frontmatter":{"title":"多元化与集中投资","description":"分散风险还是集中持股？巴菲特的策略演变"},"headers":[],"relativePath":"02_concepts/diversification.md","filePath":"02_concepts/diversification.md"}'),d={name:"02_concepts/diversification.md"};function c(p,t,b,f,k,m){const l=i("Mermaid");return e(),h("div",null,[t[1]||(t[1]=a('<h1 id="多元化与集中投资" tabindex="-1">多元化与集中投资 <a class="header-anchor" href="#多元化与集中投资" aria-label="Permalink to &quot;多元化与集中投资&quot;">​</a></h1><blockquote><p>&quot;多元化只是对无知的保护。如果你知道你在做什么，多元化是没有意义的。&quot; —— <a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>（引用约翰·梅纳德·凯恩斯语）</p></blockquote><p>巴菲特对多元化的看法经历了根本性转变。早年在合伙企业时期，他信奉广泛分散的&quot;捡烟蒂&quot;策略；后期转向高度集中的&quot;最优集中&quot;策略。这种转变本身就是价值投资思想进化的最佳案例。</p><hr><h2 id="核心出处" tabindex="-1">核心出处 <a class="header-anchor" href="#核心出处" aria-label="Permalink to &quot;核心出处&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">重点内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><a href="/01_letters/1960年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">早期对多元化的思考</td></tr><tr><td style="text-align:left;"><strong><a href="/01_letters/1977年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">伯克希尔时期的持仓集中</td></tr><tr><td style="text-align:left;"><strong><a href="/01_letters/1996年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">集中投资的前提条件</td></tr><tr><td style="text-align:left;"><strong><a href="/01_letters/2005年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">关于&quot;全部投资&quot;策略</td></tr><tr><td style="text-align:left;"><strong><a href="/01_letters/2013年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">集中持股的复利效应</td></tr></tbody></table><hr><h2 id="一、从分散到集中-策略的演变" tabindex="-1">一、从分散到集中：策略的演变 <a class="header-anchor" href="#一、从分散到集中-策略的演变" aria-label="Permalink to &quot;一、从分散到集中：策略的演变&quot;">​</a></h2><h3 id="合伙企业时期-广泛分散" tabindex="-1">合伙企业时期：广泛分散 <a class="header-anchor" href="#合伙企业时期-广泛分散" aria-label="Permalink to &quot;合伙企业时期：广泛分散&quot;">​</a></h3><p>1960年，巴菲特在合伙企业信中解释了他的分散策略：</p><blockquote><p>&quot;在合伙企业早期，我们的持仓相当分散，因为可供选择的好机会有限。&quot;</p></blockquote><blockquote><p>&quot;随着我们管理的资金规模扩大，我们开始找到更多的集中持仓机会。&quot;</p></blockquote><h3 id="伯克希尔时期-质的飞跃" tabindex="-1">伯克希尔时期：质的飞跃 <a class="header-anchor" href="#伯克希尔时期-质的飞跃" aria-label="Permalink to &quot;伯克希尔时期：质的飞跃&quot;">​</a></h3><p>1996年，巴菲特明确表示：</p><blockquote><p>&quot;在伯克希尔的持仓中，我们高度集中于少数真正优秀的公司。这种集中来自于我们对自己所做之事的确信程度。&quot;</p></blockquote><hr><h2 id="二、集中投资的前提条件" tabindex="-1">二、集中投资的前提条件 <a class="header-anchor" href="#二、集中投资的前提条件" aria-label="Permalink to &quot;二、集中投资的前提条件&quot;">​</a></h2><p>巴菲特认为，集中投资不是赌博，它需要满足两个前提：</p><blockquote><p>&quot;第一，你必须真正了解你所投资的公司。你必须能够对其未来五到十年的表现做出合理的估计。&quot;</p></blockquote><blockquote><p>&quot;第二，你的估计必须是正确的。如果你有40%的可能性是正确的，但持有一个单一的仓位，那才是真正的赌博。&quot;</p></blockquote><blockquote><p>&quot;只有在你的确信程度很高时，集中持仓才是明智的。而这种确信，来自于你对公司深入的了解。&quot;</p></blockquote><hr><h2 id="三、最优持仓数量" tabindex="-1">三、最优持仓数量 <a class="header-anchor" href="#三、最优持仓数量" aria-label="Permalink to &quot;三、最优持仓数量&quot;">​</a></h2><p>巴菲特曾表示：</p><blockquote><p>&quot;我认为对于大多数投资者来说，10只股票是合适的上限。但对于真正理解的生意，三到四只股票就够了。&quot;</p></blockquote><blockquote><p>&quot;你不是在分散风险，你是在分散无知。&quot;</p></blockquote><hr><h2 id="四、凯恩斯-vs-费雪-vs-巴菲特" tabindex="-1">四、凯恩斯 vs 费雪 vs 巴菲特 <a class="header-anchor" href="#四、凯恩斯-vs-费雪-vs-巴菲特" aria-label="Permalink to &quot;四、凯恩斯 vs 费雪 vs 巴菲特&quot;">​</a></h2><p>巴菲特同时引用了凯恩斯和费雪的观点：</p><blockquote><p>&quot;约翰·梅纳德·凯恩斯：多元化只是对无知的保护。如果你知道你在做什么，多元化是没有意义的。&quot;</p></blockquote><blockquote><p>&quot;费雪：我把鸡蛋放在少数几个篮子里，然后仔细看好这些篮子。&quot;</p></blockquote><blockquote><p>&quot;这正是我和查理的做法：我们只在少数几个地方下重注。&quot;</p></blockquote><hr><h2 id="五、集中投资的复利效应" tabindex="-1">五、集中投资的复利效应 <a class="header-anchor" href="#五、集中投资的复利效应" aria-label="Permalink to &quot;五、集中投资的复利效应&quot;">​</a></h2><p>2013年，巴菲特解释了集中投资如何加速财富积累：</p><blockquote><p>&quot;当你持有真正优秀的公司时，时间是你最好的朋友。复利的力量在集中持仓中体现得最为明显。&quot;</p></blockquote><blockquote><p>&quot;如果我们把伯克希尔的资本分散到50只普通公司，我们的复合增长率会低很多。正是对少数伟大公司的集中持有，成就了伯克希尔的复利传奇。&quot;</p></blockquote><hr><h2 id="六、巴菲特当前的持仓" tabindex="-1">六、巴菲特当前的持仓 <a class="header-anchor" href="#六、巴菲特当前的持仓" aria-label="Permalink to &quot;六、巴菲特当前的持仓&quot;">​</a></h2><p>伯克希尔的持仓极度集中：</p><blockquote><p>&quot;我们持有五六只我非常了解的公司，它们的内在价值会随时间不断增长。这是我们投资组合的全部秘密。&quot;</p></blockquote><hr><h2 id="主题关联" tabindex="-1">主题关联 <a class="header-anchor" href="#主题关联" aria-label="Permalink to &quot;主题关联&quot;">​</a></h2>',43)),(e(),s(n,null,{default:o(()=>[q(l,{id:"mermaid-194",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20A%5B%E5%A4%9A%E5%85%83%E5%8C%96%E4%B8%8E%E9%9B%86%E4%B8%AD%5D%20--%3E%20B%5B%E8%83%BD%E5%8A%9B%E5%9C%88%5D%0A%20%20%20%20A%20--%3E%20C%5B%E9%95%BF%E6%9C%9F%E4%B8%BB%E4%B9%89%5D%0A%20%20%20%20A%20--%3E%20D%5B%E9%A3%8E%E9%99%A9%5D%0A%20%20%20%20A%20--%3E%20E%5B%E7%AE%A1%E7%90%86%E5%B1%82%5D%0A%20%20%20%20A%20--%3E%20F%5B%E6%8A%A4%E5%9F%8E%E6%B2%B3%5D%0A"})]),fallback:o(()=>[...t[0]||(t[0]=[u(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=a('<hr><h2 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h2><ul><li><a href="/search.html?q=能力圈">能力圈</a> - 集中投资的前提是真正了解</li><li><a href="/search.html?q=长期主义">长期主义</a> - 集中持股的时间价值</li><li><a href="/search.html?q=风险">风险</a> - 集中投资的风险管理</li></ul><hr><p><em>本页面整理自<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>致股东信原文（1957-2024年），<a href="/search.html?q=慢慢变富的卡尔">慢慢变富的卡尔</a>编辑整理</em></p>',5))])}const x=r(d,[["render",c]]);export{E as __pageData,x as default};
